use strict;
use warnings;
use PDF::API2;
use PDF::TextExtractor;

# Function to extract text from a PDF
sub extract_text {
    my ($pdf_path) = @_;
    my $pdf = PDF::API2->open($pdf_path);
    my $text = '';
    foreach my $page (1 .. $pdf->pages) {
        my $page_obj = $pdf->page($page);
        $text .= $page_obj->text();
    }
    return $text;
}

